#include <bits/stdc++.h>
using namespace std;
int main(){
    int m;
    if(!(cin >> m)) return 0;
    vector<int> arr1(m);
    for(int i = 0; i < m; i++) cin >> arr1[i];
    int n;
    cin >> n;
    vector<int> arr2(n);
    for(int i = 0; i < n; i++) cin >> arr2[i];
    int k;
    cin >> k;
    vector<int> merged;
    merged.reserve(m + n);
    merged.insert(merged.end(), arr1.begin(), arr1.end());
    merged.insert(merged.end(), arr2.begin(), arr2.end());
    sort(merged.begin(), merged.end());
    cout << merged[k-1] << endl;
    return 0;
}
